// useState with TypeScript
interface Todo {
  id: number;
  text: string;
  done: boolean;
}

function TodoApp() {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [input, setInput] = useState<string>('');

  const addTodo = () => {
    const newTodo: Todo = {
      id: Date.now(),
      text: input,
      done: false,
    };
    setTodos(prev => [...prev, newTodo]);
    setInput('');
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInput(e.target.value);
  };

  return (
    <form onSubmit={(e: React.FormEvent) => { e.preventDefault(); addTodo(); }}>
      <input value={input} onChange={handleChange} />
      <button type="submit">추가</button>
    </form>
  );
}`,codeLang:"tsx"},{id:"testing",title:"테스팅",icon:"🧪",description:"React 컴포넌트의 테스트를 작성하는 방법을 학습합니다. Vitest, React Testing Library를 활용하여 안정적인 코드를 유지합니다.",content:[{subtitle:"테스트의 종류",items:["단위 테스트(Unit): 개별 함수/컴포넌트 테스트","통합 테스트(Integration): 여러 컴포넌트 조합 테스트","E2E 테스트: 사용자 시나리오 전체 테스트 (Playwright)","스냅샷 테스트: UI 변경 감지"]},{subtitle:"테스트 도구",items:["Vitest: Vite 기반 빠른 테스트 러너","React Testing Library: 사용자 관점 컴포넌트 테스트","MSW: API 모킹","Playwright: E2E 브라우저 테스트"]}],code:`// npm install -D vitest @testing-library/react @testing-library/jest-dom

